/**
 * ISO Screw Preview Geometry
 * Uses Three.js primitives for instant preview.
 * Visually approximate - accurate geometry is generated by JSCAD for STL export.
 */

function mergeGeometries(entries) {
  const positions = [];
  const normals = [];
  const indices = [];
  let vertexOffset = 0;

  for (const { geometry, position, rotation } of entries) {
    const matrix = new THREE.Matrix4();
    if (rotation) {
      const euler = new THREE.Euler(rotation[0], rotation[1], rotation[2]);
      matrix.makeRotationFromEuler(euler);
    }
    if (position) {
      if (rotation) {
        const posMatrix = new THREE.Matrix4().setPosition(position[0], position[1], position[2]);
        matrix.premultiply(posMatrix);
      } else {
        matrix.setPosition(position[0], position[1], position[2]);
      }
    } else if (!rotation) {
      matrix.identity();
    }

    const normalMatrix = new THREE.Matrix3().getNormalMatrix(matrix);
    const posAttr = geometry.getAttribute('position');
    const normAttr = geometry.getAttribute('normal');
    const idx = geometry.getIndex();
    const v = new THREE.Vector3();
    const n = new THREE.Vector3();

    for (let i = 0; i < posAttr.count; i++) {
      v.set(posAttr.getX(i), posAttr.getY(i), posAttr.getZ(i));
      v.applyMatrix4(matrix);
      positions.push(v.x, v.y, v.z);
      if (normAttr) {
        n.set(normAttr.getX(i), normAttr.getY(i), normAttr.getZ(i));
        n.applyMatrix3(normalMatrix).normalize();
        normals.push(n.x, n.y, n.z);
      }
    }

    if (idx) {
      for (let i = 0; i < idx.count; i++) indices.push(idx.getX(i) + vertexOffset);
    } else {
      for (let i = 0; i < posAttr.count; i++) indices.push(i + vertexOffset);
    }

    vertexOffset += posAttr.count;
    geometry.dispose();
  }

  return { positions, normals, indices };
}

/**
 * Create a threaded cylinder approximation.
 * Uses a lathe geometry with a zigzag profile to simulate thread ridges.
 */
function createThreadedCylinder(majorR, minorR, pitch, threadLength, segments) {
  // Create a profile that zigzags between minor and major radius
  const points = [];
  const numThreads = Math.ceil(threadLength / pitch);
  const actualThreads = Math.min(numThreads, 60); // Cap for performance
  const actualPitch = threadLength / actualThreads;

  // Start with a flat bottom
  points.push(new THREE.Vector2(0, 0));
  points.push(new THREE.Vector2(minorR, 0));

  // Thread profile: zigzag between minor and major
  for (let i = 0; i < actualThreads; i++) {
    const y0 = i * actualPitch;
    const yMid = y0 + actualPitch * 0.5;
    const y1 = (i + 1) * actualPitch;
    points.push(new THREE.Vector2(minorR, y0));
    points.push(new THREE.Vector2(majorR, yMid));
    points.push(new THREE.Vector2(minorR, y1));
  }

  // Cap the top
  points.push(new THREE.Vector2(0, threadLength));

  return new THREE.LatheGeometry(points, segments);
}

/**
 * Create ISO screw preview.
 * Screw axis = Y-up in Three.js (Z-up in JSCAD).
 */
export function createISOScrewPreview(params) {
  const {
    major_diameter, minor_diameter, pitch,
    actual_thread_length, shank_length, length,
    head_type, head_diameter, head_height, hex_key_size,
    segments_per_rotation
  } = params;

  const entries = [];
  const segments = Math.min(segments_per_rotation, 32);
  const majorR = major_diameter / 2;
  const minorR = minor_diameter / 2;

  // 1. Shank (unthreaded portion) - smooth cylinder at major diameter
  if (shank_length > 0.1) {
    const shank = new THREE.CylinderGeometry(majorR, majorR, shank_length, segments, 1, false);
    entries.push({ geometry: shank, position: [0, shank_length / 2, 0] });
  }

  // 2. Threaded portion - lathe geometry with thread profile
  const threadOffset = shank_length > 0.1 ? shank_length : 0;
  const threadedCyl = createThreadedCylinder(majorR, minorR, pitch, actual_thread_length, segments);
  entries.push({ geometry: threadedCyl, position: [0, threadOffset, 0] });

  // 3. Head (no socket cutout - can't subtract in Three.js, just omit internal detail)
  const headBase = length;

  if (head_type === 'hex') {
    // Hex head - 6-sided prism
    const hexR = (head_diameter / 2) / Math.cos(Math.PI / 6);
    const hexHead = new THREE.CylinderGeometry(hexR, hexR, head_height, 6);
    entries.push({ geometry: hexHead, position: [0, headBase + head_height / 2, 0] });
  } else if (head_type === 'button') {
    // Button head - dome shape using a sphere segment
    const domeR = head_diameter / 2;
    // Use a lathe profile for the dome
    const domePoints = [];
    const domeSteps = 12;
    for (let i = 0; i <= domeSteps; i++) {
      const angle = (i / domeSteps) * (Math.PI / 2);
      domePoints.push(new THREE.Vector2(Math.cos(angle) * domeR, Math.sin(angle) * head_height));
    }
    const domeGeo = new THREE.LatheGeometry(domePoints, segments);
    entries.push({ geometry: domeGeo, position: [0, headBase, 0] });
  } else if (head_type === 'flat') {
    // Flat/countersunk - tapered cone
    const flatHeight = head_height * 0.6;
    const flatHead = new THREE.CylinderGeometry(head_diameter / 2, majorR, flatHeight, segments, 1, false);
    entries.push({ geometry: flatHead, position: [0, headBase + flatHeight / 2, 0] });
  } else {
    // Socket cap (default) - cylinder
    const capHead = new THREE.CylinderGeometry(head_diameter / 2, head_diameter / 2, head_height, segments, 1, false);
    entries.push({ geometry: capHead, position: [0, headBase + head_height / 2, 0] });
  }

  // 4. Chamfer on the tip of the screw (small cone)
  const chamferHeight = majorR * 0.5;
  const tipCone = new THREE.ConeGeometry(majorR, chamferHeight, segments);
  entries.push({ geometry: tipCone, position: [0, -chamferHeight / 2, 0] });

  return mergeGeometries(entries);
}

export default { createISOScrewPreview };
